import{_ as e,o,c as a,ag as i}from"./chunks/framework.CvgP6Fyv.js";const h=JSON.parse('{"title":"PDF Customization","description":"","frontmatter":{},"headers":[],"relativePath":"settings/pdf.md","filePath":"settings/pdf.md"}'),n={name:"settings/pdf.md"};function r(s,t,l,u,d,c){return o(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="pdf-customization" tabindex="-1">PDF Customization <a class="header-anchor" href="#pdf-customization" aria-label="Permalink to &quot;PDF Customization&quot;">​</a></h1><p>Customize the appearance of your invoice, quote, and credit note PDFs to match your brand.</p><h2 id="pdf-editor" tabindex="-1">PDF Editor <a class="header-anchor" href="#pdf-editor" aria-label="Permalink to &quot;PDF Editor&quot;">​</a></h2><p>The visual PDF editor lets you customize your document layout with a live preview.</p><h3 id="accessing-the-editor" tabindex="-1">Accessing the editor <a class="header-anchor" href="#accessing-the-editor" aria-label="Permalink to &quot;Accessing the editor&quot;">​</a></h3><p>Go to <strong>Company &gt; PDF Editor</strong> or access it from Company &gt; Branding.</p><h3 id="customization-options" tabindex="-1">Customization options <a class="header-anchor" href="#customization-options" aria-label="Permalink to &quot;Customization options&quot;">​</a></h3><h4 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h4><ul><li><strong>Logo position and size</strong> — Place your logo where it looks best</li><li><strong>Company info placement</strong> — Position your business details</li><li><strong>Customer info placement</strong> — Where customer details appear</li><li><strong>Line item table</strong> — Column widths and alignment</li></ul><h4 id="content" tabindex="-1">Content <a class="header-anchor" href="#content" aria-label="Permalink to &quot;Content&quot;">​</a></h4><p>Choose which fields to show or hide:</p><ul><li>Company VAT number</li><li>Company registration number</li><li>IBAN / bank details</li><li>Payment terms</li><li>Notes section</li><li>Footer text</li></ul><h4 id="styling" tabindex="-1">Styling <a class="header-anchor" href="#styling" aria-label="Permalink to &quot;Styling&quot;">​</a></h4><ul><li><strong>Font</strong> — Choose from available typefaces</li><li><strong>Font size</strong> — Adjust text sizing</li><li><strong>Accent color</strong> — Your brand color for headers and accents</li><li><strong>Line spacing</strong> — Adjust document density</li></ul><h3 id="preview" tabindex="-1">Preview <a class="header-anchor" href="#preview" aria-label="Permalink to &quot;Preview&quot;">​</a></h3><p>The editor shows a real-time preview using sample data. You can also generate a <strong>sample PDF</strong> to see exactly how a printed invoice will look.</p><h2 id="document-types" tabindex="-1">Document types <a class="header-anchor" href="#document-types" aria-label="Permalink to &quot;Document types&quot;">​</a></h2><p>PDF settings apply to all generated documents:</p><ul><li><strong>Invoices</strong> — Standard billing documents</li><li><strong>Quotes</strong> — Quotation documents</li><li><strong>Credit notes</strong> — Refund/adjustment documents</li><li><strong>Reminders</strong> — Payment reminder documents</li></ul><h2 id="language-support" tabindex="-1">Language support <a class="header-anchor" href="#language-support" aria-label="Permalink to &quot;Language support&quot;">​</a></h2><p>PDFs are generated in the language of the invoice. If you send an invoice in German, the PDF labels (like &quot;Invoice&quot;, &quot;Due Date&quot;, &quot;Total&quot;) appear in German.</p><p>Supported PDF languages: English, Dutch, German, French.</p><h2 id="logo-requirements" tabindex="-1">Logo requirements <a class="header-anchor" href="#logo-requirements" aria-label="Permalink to &quot;Logo requirements&quot;">​</a></h2><p>For best results:</p><ul><li><strong>Format:</strong> PNG with transparent background (recommended), JPG, or SVG</li><li><strong>Resolution:</strong> At least 300px wide</li><li><strong>Aspect ratio:</strong> Landscape or square logos work best</li><li><strong>File size:</strong> Under 2MB</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>SVG logos are automatically converted to PNG for email compatibility.</p></div><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Generate a sample PDF after making changes to verify the layout</li><li>Use your brand&#39;s accent color for a professional look</li><li>Keep the layout clean — don&#39;t overcrowd the PDF with too much information</li><li>Test with a real invoice (to yourself) before sending to customers</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Advanced PDF customization requires the <strong>Pro</strong> plan or higher.</p></div>',29)])])}const m=e(n,[["render",r]]);export{h as __pageData,m as default};
